    <h1 class="mb-4">Job Application</h1>

    @* ───── Step Indicator Bar ───── *@
    <nav class="step-indicator mb-4" aria-label="Application steps">
        @for (int i = 0; i < StepLabels.Length; i++)
        {
            var step = i;
            var state = step == _currentStep ? "active"
                      : step < _currentStep ? "completed"
                      : "upcoming";

            <button class="step-item @state"
                    disabled="@(step > _currentStep)"
                    @onclick="() => GoToStep(step)">
                <span class="step-circle">
                    @if (step < _currentStep)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(step + 1)</span>
                    }
                </span>
                <span class="step-label">@StepLabels[step]</span>
            </button>

            @if (step < StepLabels.Length - 1)
            {
                <span class="step-connector @(step < _currentStep ? "completed" : "")"></span>
            }
        }
    </nav>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger" role="alert">@_errorMessage</div>
    }

    @* ───── Step 1: Personal Info ───── *@
    @if (_currentStep == 0)
    {
        <div class="card">
            <div class="card-header"><h4 class="mb-0">Personal Information</h4></div>
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Full Name <span class="text-danger">*</span></label>
                    <input class="form-control" @bind="_fullName" placeholder="Jane Doe" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="_email" placeholder="jane@example.com" />
                    @if (!string.IsNullOrEmpty(_emailError))
                    {
                        <div class="text-danger mt-1">@_emailError</div>
                    }
                </div>
                <div class="mb-3">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" @bind="_phone" placeholder="(555) 123-4567" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Address <span class="text-danger">*</span></label>
                    <textarea class="form-control" @bind="_address" rows="2" placeholder="123 Main St, City, State ZIP"></textarea>
                </div>
                <div class="d-flex justify-content-end">
                    <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@_isValidating">
                        @if (_isValidating)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Next
                    </button>
                </div>
            </div>
        </div>
    }

    @* ───── Step 2: Work History ───── *@
    @if (_currentStep == 1)
    {
        <div class="card">
            <div class="card-header"><h4 class="mb-0">Work History</h4></div>
            <div class="card-body">
                @for (int i = 0; i < _workEntries.Count; i++)
                {
                    var idx = i;
                    <div class="border rounded p-3 mb-3 position-relative">
                        <h5>Position @(idx + 1)</h5>

                        @if (_workEntries.Count > 1)
                        {
                            <button class="btn btn-sm btn-outline-danger position-absolute top-0 end-0 m-2"
                                    @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                        }

                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Company <span class="text-danger">*</span></label>
                                <input class="form-control" @bind="_workEntries[idx].Company" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                                <input class="form-control" @bind="_workEntries[idx].Title" />
                            </div>
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-4">
                                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                                <input type="date" class="form-control" @bind="_workEntries[idx].StartDate" />
                            </div>
                            <div class="col-md-4">
                                <label class="form-label">End Date</label>
                                <input type="date" class="form-control" @bind="_workEntries[idx].EndDate"
                                       disabled="@_workEntries[idx].IsCurrent" />
                            </div>
                            <div class="col-md-4 d-flex align-items-end mb-1">
                                <div class="form-check">
                                    <input type="checkbox" class="form-check-input" id="current-@idx"
                                           @bind="_workEntries[idx].IsCurrent" />
                                    <label class="form-check-label" for="current-@idx">I currently work here</label>
                                </div>
                            </div>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Description</label>
                            <textarea class="form-control" @bind="_workEntries[idx].Description" rows="2"></textarea>
                        </div>
                    </div>
                }

                <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">
                    + Add Another Position
                </button>

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="Back">Back</button>
                    <button class="btn btn-primary" @onclick="NextFromWorkHistory">Next</button>
                </div>
            </div>
        </div>
    }

    @* ───── Step 3: References ───── *@
    @if (_currentStep == 2)
    {
        <div class="card">
            <div class="card-header"><h4 class="mb-0">References</h4></div>
            <div class="card-body">
                @for (int i = 0; i < _references.Count; i++)
                {
                    var idx = i;
                    <div class="border rounded p-3 mb-3 position-relative">
                        <h5>Reference @(idx + 1)</h5>

                        @if (_references.Count > 1)
                        {
                            <button class="btn btn-sm btn-outline-danger position-absolute top-0 end-0 m-2"
                                    @onclick="() => RemoveReference(idx)">Remove</button>
                        }

                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Name <span class="text-danger">*</span></label>
                                <input class="form-control" @bind="_references[idx].Name" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                                <input class="form-control" @bind="_references[idx].Relationship" placeholder="e.g. Former Manager" />
                            </div>
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Email <span class="text-danger">*</span></label>
                                <input type="email" class="form-control" @bind="_references[idx].Email" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Phone <span class="text-danger">*</span></label>
                                <input type="tel" class="form-control" @bind="_references[idx].Phone" />
                            </div>
                        </div>
                    </div>
                }

                @if (_references.Count < 3)
                {
                    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
                        + Add Reference
                    </button>
                }

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="Back">Back</button>
                    <button class="btn btn-primary" @onclick="NextFromReferences">Next</button>
                </div>
            </div>
        </div>
    }

    @* ───── Step 4: Cover Letter ───── *@
    @if (_currentStep == 3)
    {
        <div class="card">
            <div class="card-header"><h4 class="mb-0">Cover Letter</h4></div>
            <div class="card-body">
                <div class="mb-2">
                    <textarea class="form-control" @bind="_coverLetter" @bind:event="oninput" rows="12"
                              placeholder="Tell us why you'd be a great fit…" maxlength="2000"></textarea>
                </div>
                <div class="text-muted mb-3">@(_coverLetter?.Length ?? 0) / 2000 characters</div>

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="Back">Back</button>
                    <button class="btn btn-primary" @onclick="NextFromCoverLetter">Next</button>
                </div>
            </div>
        </div>
    }

    @* ───── Step 5: Review & Submit ───── *@
    @if (_currentStep == 4)
    {
        @if (_submitted)
        {
            <div class="card border-success">
                <div class="card-body text-center py-5">
                    <h2 class="text-success mb-3">&#10003; Application Submitted!</h2>
                    <p class="lead">Your application ID is <strong>#@_applicationId</strong>.</p>
                    <p>Thank you for applying. We'll be in touch soon.</p>
                </div>
            </div>
        }
        else
        {
            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <h5 class="mb-0">Personal Information</h5>
                    <button class="btn btn-sm btn-link" @onclick='() => GoToStep(0)'>Edit</button>
                </div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@_fullName</dd>
                        <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@_email</dd>
                        <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@_phone</dd>
                        <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@_address</dd>
                    </dl>
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <h5 class="mb-0">Work History</h5>
                    <button class="btn btn-sm btn-link" @onclick='() => GoToStep(1)'>Edit</button>
                </div>
                <div class="card-body">
                    @foreach (var entry in _workEntries)
                    {
                        <div class="mb-3">
                            <strong>@entry.Title</strong> at @entry.Company<br />
                            <span class="text-muted">
                                @entry.StartDate.ToString("MMM yyyy") &ndash;
                                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                            </span>
                            @if (!string.IsNullOrWhiteSpace(entry.Description))
                            {
                                <p class="mt-1 mb-0">@entry.Description</p>
                            }
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <h5 class="mb-0">References</h5>
                    <button class="btn btn-sm btn-link" @onclick='() => GoToStep(2)'>Edit</button>
                </div>
                <div class="card-body">
                    @foreach (var r in _references)
                    {
                        <div class="mb-2">
                            <strong>@r.Name</strong> — @r.Relationship<br />
                            <span class="text-muted">@r.Email · @r.Phone</span>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <h5 class="mb-0">Cover Letter</h5>
                    <button class="btn btn-sm btn-link" @onclick='() => GoToStep(3)'>Edit</button>
                </div>
                <div class="card-body">
                    <p style="white-space: pre-wrap;">@_coverLetter</p>
                </div>
            </div>

            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="Back">Back</button>
                <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isSubmitting">
                    @if (_isSubmitting)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Submit Application
                </button>
            </div>
        }
    }
</div>

@code {
    private static readonly string[] StepLabels =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private int _currentStep;
    private string _errorMessage = string.Empty;

    // Step 1
    private string _fullName = string.Empty;
    private string _email = string.Empty;
    private string _phone = string.Empty;
    private string _address = string.Empty;
    private string _emailError = string.Empty;
    private bool _isValidating;

    // Step 2
    private List<WorkEntryModel> _workEntries = [new()];

    // Step 3
    private List<ReferenceModel> _references = [new()];

    // Step 4
    private string _coverLetter = string.Empty;

    // Step 5
    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;

    // ───── Navigation ─────

    private void GoToStep(int step)
    {
        if (step <= _currentStep)
        {
            _errorMessage = string.Empty;
            _currentStep = step;
        }
    }

    private void Back()
    {
        _errorMessage = string.Empty;
        if (_currentStep > 0) _currentStep--;
    }

    // ───── Step 1 validation ─────

    private async Task NextFromPersonalInfo()
    {
        _errorMessage = string.Empty;
        _emailError = string.Empty;

        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email)
            || string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _errorMessage = "Please fill in all required fields.";
            return;
        }

        _isValidating = true;
        try
        {
            var valid = await ApplicationService.ValidateEmailAsync(_email);
            if (!valid)
            {
                _emailError = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            _isValidating = false;
        }

        _currentStep = 1;
    }

    // ───── Step 2 validation ─────

    private void NextFromWorkHistory()
    {
        _errorMessage = string.Empty;
        foreach (var e in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title)
                || e.StartDate == default)
            {
                _errorMessage = "Please fill in the company, title, and start date for every position.";
                return;
            }
        }
        _currentStep = 2;
    }

    private void AddWorkEntry() => _workEntries.Add(new WorkEntryModel());

    private void RemoveWorkEntry(int index)
    {
        if (_workEntries.Count > 1)
            _workEntries.RemoveAt(index);
    }

    // ───── Step 3 validation ─────

    private void NextFromReferences()
    {
        _errorMessage = string.Empty;
        foreach (var r in _references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _errorMessage = "Please fill in all fields for every reference.";
                return;
            }
        }
        _currentStep = 3;
    }

    private void AddReference()
    {
        if (_references.Count < 3) _references.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (_references.Count > 1) _references.RemoveAt(index);
    }

    // ───── Step 4 validation ─────

    private void NextFromCoverLetter()
    {
        _errorMessage = string.Empty;
        if (string.IsNullOrWhiteSpace(_coverLetter))
        {
            _errorMessage = "Please write a cover letter before proceeding.";
            return;
        }
        _currentStep = 4;
    }

    // ───── Submit ─────

    private async Task SubmitApplication()
    {
        _isSubmitting = true;
        _errorMessage = string.Empty;

        try
        {
            var application = new JobApplication(
                new PersonalInfo(_fullName, _email, _phone, _address),
                new WorkHistory(_workEntries.Select(e =>
                    new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description ?? "")
                ).ToList()),
                _references.Select(r =>
                    new Reference(r.Name, r.Relationship, r.Email, r.Phone)
                ).ToList(),
                _coverLetter
            );

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    // ───── View models for two-way binding ─────

    private class WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string? Description { get; set; }
    }

    private class ReferenceModel
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }
}

